prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?modelId ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:originalId ?modelId ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?pg a bboExt:ParallelGateway ;
      tai:belongsTo ?choreo .
} 
ORDER BY ?created
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?gwType ?gwCount WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .

  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?gw a ?gwType ; tai:belongsTo ?choreo .
  FILTER(?gwType IN (bboExt:ParallelGateway, bboExt:ExclusiveGateway, bboExt:EventBasedGateway))

  {
    SELECT ?model ?gwType (COUNT(DISTINCT ?gw) AS ?gwCount) WHERE {
      ?org a bboExt:Organization ; tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .
      ?model a bboExt:Model ; tai:belongsTo ?org .
      ?defs tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
      ?gw a ?gwType ; tai:belongsTo ?choreo .
      FILTER(?gwType IN (bboExt:ParallelGateway, bboExt:ExclusiveGateway, bboExt:EventBasedGateway))
    }
    GROUP BY ?model ?gwType
  }
}
ORDER BY DESC(?gwCount) ?created
LIMIT 25
